const brand = $input.item.json;
const replies = [
  { type: 'interesado', text: 'Sí me interesa, ¿cómo funciona el proceso de integración con el Marketplace?', es_opt_out: false },
  { type: 'objeción', text: 'Las comisiones del marketplace me parecen muy altas comparado con vender directo', es_opt_out: false },
  { type: 'opt-out', text: 'Por favor no me vuelvan a escribir, no me interesa para nada', es_opt_out: true }
];
return replies.map(reply => ({
  json: {
    brand_id: brand.brand_id,
    category: brand.category,
    gmv_cop_millions_12m: brand.gmv_cop_millions_12m,
    gmv_90d_to_12m_ratio: brand.gmv_90d_to_12m_ratio,
    final_score: brand.final_score,
    reply_type: reply.type,
    reply_text: reply.text,
    es_opt_out: reply.es_opt_out
  }
}));

const item = $input.item.json;
if (item.es_opt_out) {
  return { json: { brand_id: item.brand_id, reply_text: item.reply_text, reply_type: item.reply_type, classification: { intent_score: 0, is_decision_maker: false, objection_type: null, suggested_action: 'descartar', reasoning: 'Opt-out explícito del merchant' }, groq_called: false, gate_opt_out_active: true } };
}
const systemPrompt = `Eres el clasificador de leads. Responde SOLO en JSON: {"intent_score": <0-100>, "is_decision_maker": <true|false>, "objection_type": <null|"precio"|"integracion">, "suggested_action": <"agendar"|"nurture"|"descartar">, "reasoning": "<corta>"}. Brand: ${item.brand_id}, ${item.category}, GMV ${item.gmv_cop_millions_12m}MM, crecimiento ${Math.round(item.gmv_90d_to_12m_ratio*100)}%, score ${item.final_score}/100. Reglas: 70-100=agendar, 40-69=nurture, 0-39=descartar. IMPORTANTE: suggested_action debe ser EXACTAMENTE una de estas 3 palabras, sin texto adicional: agendar, nurture, descartar. El detalle o razón va en reasoning, NO en suggested_action.`;
return { json: { brand_id: item.brand_id, category: item.category, reply_text: item.reply_text, reply_type: item.reply_type, systemPrompt: systemPrompt, userMessage: `Reply: "${item.reply_text}"`, groq_called: true } };

const item = $input.item.json;
if (!item.groq_called) { return { json: { brand_id: item.brand_id, reply_text: item.reply_text, reply_type: item.reply_type, classification: item.classification, groq_called: false, gate_opt_out_active: item.gate_opt_out_active } }; }
let raw = $input.item.json.choices[0].message.content.trim();
raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
let classification;
try { classification = JSON.parse(raw); } catch (e) { console.log('ERROR:', raw); classification = { intent_score: 0, is_decision_maker: false, objection_type: null, suggested_action: 'descartar', reasoning: 'Error en clasificación' }; }
const intentScore = Number.isFinite(Number(classification.intent_score)) ? Number(classification.intent_score) : 0;
const suggestedAction = ['agendar', 'nurture', 'descartar'].includes(String(classification.suggested_action || '').trim().toLowerCase()) ? String(classification.suggested_action).trim().toLowerCase() : (intentScore >= 70 ? 'agendar' : intentScore >= 40 ? 'nurture' : 'descartar');
classification.intent_score = intentScore;
classification.suggested_action = suggestedAction;
return { json: { brand_id: item.brand_id, category: item.category, reply_text: item.reply_text, reply_type: item.reply_type, classification: classification, groq_called: true, gate_opt_out_active: false, timestamp: new Date().toISOString() } };
